#!/usr/bin/env python3
"""Instalador automatico do Conferidor de Loterias Caixa.
Execute: python instalar.py
"""
import base64, zlib, json, os, sys, subprocess

DATA = ""

def main():
    print("\n=== Instalador - Conferidor de Loterias Caixa ===\n")
    raw = zlib.decompress(base64.b64decode(DATA))
    files = json.loads(raw.decode("utf-8"))

    dest = os.path.join(os.getcwd(), "loterias-caixa")
    if os.path.exists(dest):
        resp = input(f"Pasta \'loterias-caixa\' ja existe. Sobrescrever? (s/n): ")
        if resp.lower() != "s":
            sys.exit(0)

    print(f"Criando projeto em: {dest}\n")
    for path, content in files.items():
        full = os.path.join(dest, path.replace("/", os.sep))
        os.makedirs(os.path.dirname(full), exist_ok=True)
        with open(full, "w", encoding="utf-8") as f:
            f.write(content)
        print(f"  ✓ {path}")

    os.makedirs(os.path.join(dest, "data"),    exist_ok=True)
    os.makedirs(os.path.join(dest, "exports"), exist_ok=True)

    print("\nInstalando dependencias...")
    subprocess.check_call([sys.executable, "-m", "pip", "install",
                           "rich", "questionary", "openpyxl", "-q"])

    print("\n✅ Pronto! Para rodar:\n")
    print(f"  cd loterias-caixa")
    print(f"  python main.py\n")

if __name__ == "__main__":
    main()
